/**
 * Minimal Chart.js replacement — supports only Bar chart
 * Drop-in for: new Chart(ctx, config)
 * API-compatible with dashboard.js usage
 */
(function (global) {
  "use strict";

  function Chart(ctx, config) {
    this.ctx = ctx;
    this.canvas = ctx.canvas;
    this.config = config;
    this.type = config.type || "bar";
    this.data = config.data || { labels: [], datasets: [] };
    this.options = config.options || {};
    this._animationFrame = null;
    this._resizeHandler = null;
    this._init();
  }

  Chart.prototype._init = function () {
    var self = this;
    if (this.options.responsive !== false) {
      this.canvas.style.width = "100%";
      this.canvas.style.height = "100%";
      this._resizeHandler = function () {
        self._resize();
        self._draw();
      };
      window.addEventListener("resize", this._resizeHandler);
    }
    this._resize();

    var duration =
      this.options.animation && this.options.animation.duration != null
        ? this.options.animation.duration
        : 750;

    if (duration > 0) {
      this._animate(duration);
    } else {
      this._progress = 1;
      this._easedProgress = 1;
      this._draw();
    }
  };

  Chart.prototype._resize = function () {
    var parent = this.canvas.parentElement;
    if (parent) {
      var w = parent.clientWidth || 300;
      var h = parent.clientHeight || 300;
      var dpr = window.devicePixelRatio || 1;
      this.canvas.width = w * dpr;
      this.canvas.height = h * dpr;
      this.canvas.style.width = w + "px";
      this.canvas.style.height = h + "px";
      this.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      this._width = w;
      this._height = h;
    }
  };

  Chart.prototype._animate = function (duration) {
    var self = this;
    var start = performance.now();
    function step(now) {
      var elapsed = now - start;
      self._progress = Math.min(elapsed / duration, 1);
      var t = self._progress;
      // easeOutQuart — احساس سبک‌تر و روان‌تر
      t = 1 - Math.pow(1 - t, 4);
      self._easedProgress = t;
      self._draw();
      if (self._progress < 1) {
        self._animationFrame = requestAnimationFrame(step);
      }
    }
    this._animationFrame = requestAnimationFrame(step);
  };

  Chart.prototype._draw = function () {
    var ctx = this.ctx;
    var w = this._width;
    var h = this._height;
    var progress = this._easedProgress != null ? this._easedProgress : 1;
    ctx.clearRect(0, 0, w, h);
    if (this.type === "bar") {
      this._drawBar(ctx, w, h, progress);
    }
  };

  Chart.prototype._drawBar = function (ctx, w, h, progress) {
    var data = this.data;
    var labels = data.labels || [];
    var datasets = data.datasets || [];
    if (labels.length === 0 || datasets.length === 0) return;

    var opts = this.options || {};
    var scales = opts.scales || {};
    var yScale = scales.y || {};
    var xScale = scales.x || {};
    var plugins = opts.plugins || {};
    var legendOpts = plugins.legend || {};
    var tooltipOpts = plugins.tooltip || {};

    // ─── Layout ──────────────────────────────────────────────
    var legendH = legendOpts.display !== false ? 32 : 0;
    var padTop    = legendH + 16;   // فضای بالا + legend
    var padBottom = 56;             // فضای برچسب X
    var padLeft   = 80;             // فضای کافی برای اعداد Y
    var padRight  = 24;

    var chartW = Math.max(w - padLeft - padRight, 10);
    var chartH = Math.max(h - padTop - padBottom, 10);

    // ─── Y Scale ─────────────────────────────────────────────
    var values = datasets[0].data || [];
    var maxVal = Math.max.apply(null, values.concat([0]));
    if (maxVal === 0) maxVal = 1;
    var niceMax  = this._niceNum(maxVal);
    var tickCount = 5;
    var tickStep  = niceMax / tickCount;

    // ─── Style ───────────────────────────────────────────────
    var bgColor     = datasets[0].backgroundColor || "rgba(0,212,255,0.65)";
    var borderColor = datasets[0].borderColor      || "#00d4ff";
    var borderWidth = datasets[0].borderWidth != null ? datasets[0].borderWidth : 1.5;
    var borderRadius = datasets[0].borderRadius != null ? datasets[0].borderRadius : 5;

    var yTickColor = (yScale.ticks && yScale.ticks.color) || "#7b86a";
    var yTickFont  = (yScale.ticks && yScale.ticks.font)  || { family: "JetBrains Mono, monospace", size: 11 };
    var yGridColor = (yScale.grid  && yScale.grid.color)  || "rgba(255,255,255,0.06)";

    var xTickColor = (xScale.ticks && xScale.ticks.color) || "#7b86a0";
    var xTickFont  = (xScale.ticks && xScale.ticks.font)  || { family: "Noto Sans Arabic, sans-serif", size: 11 };

    var legendColor = (legendOpts.labels && legendOpts.labels.color) || "#e4e8f0";
    var legendFont  = (legendOpts.labels && legendOpts.labels.font)  || { family: "Noto Sans Arabic, sans-serif", size: 13 };

    // ─── Legend ──────────────────────────────────────────────
    if (legendOpts.display !== false && datasets[0].label) {
      var lx = padLeft;
      var ly = 10;
      ctx.save();
      // مربع رنگی با گوشه‌های گرد
      this._roundRect(ctx, lx, ly, 14, 14, 3, true);
      ctx.fillStyle = bgColor;
      ctx.fill();

      ctx.fillStyle = legendColor;
      ctx.font = (legendFont.size || 13) + "px " + (legendFont.family || "sans-serif");
      ctx.textAlign = "left";
      ctx.textBaseline = "middle";
      ctx.fillText(datasets[0].label, lx + 20, ly + 7);
      ctx.restore();
    }

    // ─── Y axis baseline ─────────────────────────────────────
    ctx.save();
    ctx.strokeStyle = "rgba(255,255,255,0.1)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(padLeft, padTop);
    ctx.lineTo(padLeft, padTop + chartH);
    ctx.stroke();
    ctx.restore();

    // ─── Y grid + tick labels ─────────────────────────────────
    ctx.save();
    for (var i = 0; i <= tickCount; i++) {
      var val = tickStep * i;
      var gy  = padTop + chartH - (val / niceMax) * chartH;

      // grid line
      if (yScale.grid && yScale.grid.display !== false) {
        ctx.strokeStyle = yGridColor;
        ctx.lineWidth   = i === 0 ? 1.5 : 1;
        ctx.setLineDash(i === 0 ? [] : [4, 4]);
        ctx.beginPath();
        ctx.moveTo(padLeft, gy);
        ctx.lineTo(padLeft + chartW, gy);
        ctx.stroke();
        ctx.setLineDash([]);
      }

      // tick label
      var tickLabel = Math.round(val).toLocaleString("fa-IR");
      if (yScale.ticks && typeof yScale.ticks.callback === "function") {
        tickLabel = yScale.ticks.callback(Math.round(val));
      }
      ctx.fillStyle    = yTickColor;
      ctx.font         = (yTickFont.size || 11) + "px " + (yTickFont.family || "monospace");
      ctx.textAlign    = "right";
      ctx.textBaseline = "middle";
      ctx.fillText(tickLabel, padLeft - 10, gy);
    }
    ctx.restore();

    // ─── Bars ────────────────────────────────────────────────
    var barCount = labels.length;
    var minGap   = 6;

    // عرض bar به صورت نسبی از فضای موجود
    var barW = Math.floor((chartW / barCount) * 0.55);
    barW = Math.max(barW, 6);
    barW = Math.min(barW, 64);

    var totalBarsW = barCount * barW + (barCount - 1) * minGap;
    // اگر جا نبود gap رو کم کن
    var gap = barCount > 1
      ? Math.max((chartW - barCount * barW) / (barCount - 1), minGap)
      : 0;

    var startX = padLeft + (chartW - (barCount * barW + (barCount - 1) * gap)) / 2;

    this._bars = [];
    ctx.save();

    for (var j = 0; j < barCount; j++) {
      var v    = values[j] || 0;
      var barH = (v / niceMax) * chartH * progress;
      var bx   = startX + j * (barW + gap);
      var barY = padTop + chartH - barH;

      if (barH < 1) {
        this._bars.push({ x: bx, y: padTop + chartH, w: barW, h: 0, value: v, label: labels[j] });
        continue;
      }

      // سایه ملایم زیر bar
      ctx.save();
      ctx.shadowColor   = borderColor;
      ctx.shadowBlur    = 6;
      ctx.shadowOffsetY = 2;

      // fill
      ctx.fillStyle = bgColor;
      this._roundRectTop(ctx, bx, barY, barW, barH, borderRadius);
      ctx.fill();
      ctx.restore();

      // border
      if (borderWidth > 0) {
        ctx.strokeStyle = borderColor;
        ctx.lineWidth   = borderWidth;
        this._roundRectTop(ctx, bx, barY, barW, barH, borderRadius);
        ctx.stroke();
      }

      this._bars.push({ x: bx, y: barY, w: barW, h: barH, value: v, label: labels[j] });
    }
    ctx.restore();

    // ─── X tick labels ───────────────────────────────────────
    ctx.save();
    ctx.fillStyle    = xTickColor;
    ctx.font         = (xTickFont.size || 11) + "px " + (xTickFont.family || "sans-serif");
    ctx.textBaseline = "top";

    var maxRotation = (xScale.ticks && xScale.ticks.maxRotation != null)
      ? xScale.ticks.maxRotation : 40;
    var rotation = (maxRotation * Math.PI) / 180;

    for (var k = 0; k < barCount; k++) {
      var cx = startX + k * (barW + gap) + barW / 2;
      var cy = padTop + chartH + 10;
      ctx.save();
      ctx.translate(cx, cy);
      if (maxRotation !== 0) {
        ctx.rotate(-rotation);   // منفی = چرخش به سمت چپ (خواناتر برای فارسی)
        ctx.textAlign = "right";
      } else {
        ctx.textAlign = "center";
      }
      ctx.fillText(labels[k], 0, 0);
      ctx.restore();
    }
    ctx.restore();

    // ─── Tooltip ─────────────────────────────────────────────
    this._bindTooltip(tooltipOpts, datasets[0]);
  };

  // گوشه‌های گرد فقط بالا (برای bar)
  Chart.prototype._roundRectTop = function (ctx, x, y, w, h, r) {
    if (h <= 0) return;
    if (r > h) r = h;
    if (r > w / 2) r = w / 2;
    r = Math.max(r, 0);
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h);
    ctx.lineTo(x, y + h);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  // گوشه‌های گرد کامل (برای legend swatch)
  Chart.prototype._roundRect = function (ctx, x, y, w, h, r) {
    if (r > Math.min(w, h) / 2) r = Math.min(w, h) / 2;
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  Chart.prototype._bindTooltip = function (tooltipOpts, dataset) {
    var self   = this;
    var canvas = this.canvas;

    if (this._tooltipHandler) {
      canvas.removeEventListener("mousemove",  this._tooltipHandler);
      canvas.removeEventListener("mouseleave", this._tooltipLeave);
    }

    this._tooltipHandler = function (e) {
      var rect = canvas.getBoundingClientRect();
      var mx   = e.clientX - rect.left;
      var my   = e.clientY - rect.top;
      var bars = self._bars || [];
      var found = null;

      for (var i = 0; i < bars.length; i++) {
        var b = bars[i];
        // ناحیه hover کمی گسترده‌تر از bar (±4px افقی)
        if (mx >= b.x - 4 && mx <= b.x + b.w + 4 && my >= b.y && my <= b.y + b.h) {
          found = b;
          break;
        }
      }

      var old = document.getElementById("_chart_tooltip");
      if (old) old.remove();

      if (found) {
        canvas.style.cursor = "pointer";

        var bgCol   = tooltipOpts.backgroundColor || "rgba(16,20,32,0.96)";
        var titleCol = tooltipOpts.titleColor     || "#00d4ff";
        var bodyCol  = tooltipOpts.bodyColor      || "#e4e8f0";
        var brdCol   = tooltipOpts.borderColor    || "rgba(0,212,255,0.35)";
        var brdW     = tooltipOpts.borderWidth    != null ? tooltipOpts.borderWidth : 1;
        var pad      = tooltipOpts.padding        != null ? tooltipOpts.padding     : 10;

        var tip = document.createElement("div");
        tip.id = "_chart_tooltip";
        tip.style.cssText =
          "position:fixed;z-index:99999;pointer-events:none;" +
          "background:"    + bgCol   + ";" +
          "color:"         + bodyCol + ";" +
          "border:"        + brdW + "px solid " + brdCol + ";" +
          "border-radius:8px;" +
          "padding:"       + pad + "px " + (pad + 4) + "px;" +
          "font:12px 'Noto Sans Arabic',sans-serif;" +
          "box-shadow:0 4px 16px rgba(0,0,0,0.4);" +
          "direction:rtl;" +
          "min-width:80px;text-align:center;";

        var labelText = found.value.toLocaleString("fa-IR");
        if (tooltipOpts.callbacks && typeof tooltipOpts.callbacks.label === "function") {
          labelText = tooltipOpts.callbacks.label({
            parsed: { y: found.value },
            label:  found.label,
          });
        }

        tip.innerHTML =
          '<div style="color:' + titleCol + ';font-size:11px;margin-bottom:5px;opacity:.85">' +
          found.label + "</div>" +
          '<div style="font-size:14px;font-weight:600">' + labelText + "</div>";

        document.body.appendChild(tip);

        // موقعیت هوشمند — tooltip بالای موس قرار میگیره و از لبه خارج نمیشه
        var tipRect = tip.getBoundingClientRect();
        var tx = e.clientX - tipRect.width / 2;
        var ty = e.clientY - tipRect.height - 14;
        if (tx < 4) tx = 4;
        if (tx + tipRect.width > window.innerWidth - 4)
          tx = window.innerWidth - tipRect.width - 4;
        if (ty < 4) ty = e.clientY + 14;

        tip.style.left = tx + "px";
        tip.style.top  = ty + "px";
      } else {
        canvas.style.cursor = "default";
      }
    };

    this._tooltipLeave = function () {
      var old = document.getElementById("_chart_tooltip");
      if (old) old.remove();
      canvas.style.cursor = "default";
    };

    canvas.addEventListener("mousemove",  this._tooltipHandler);
    canvas.addEventListener("mouseleave", this._tooltipLeave);
  };

  Chart.prototype._niceNum = function (val) {
    if (val <= 0) return 1;
    var exp  = Math.floor(Math.log10(val));
    var frac = val / Math.pow(10, exp);
    var nice;
    if (frac <= 1)      nice = 1;
    else if (frac <= 2) nice = 2;
    else if (frac <= 5) nice = 5;
    else                nice = 10;
    return nice * Math.pow(10, exp);
  };

  Chart.prototype.destroy = function () {
    if (this._animationFrame)  cancelAnimationFrame(this._animationFrame);
    if (this._resizeHandler)   window.removeEventListener("resize", this._resizeHandler);
    if (this._tooltipHandler) {
      this.canvas.removeEventListener("mousemove",  this._tooltipHandler);
      this.canvas.removeEventListener("mouseleave", this._tooltipLeave);
    }
    var old = document.getElementById("_chart_tooltip");
    if (old) old.remove();
    this.ctx.clearRect(0, 0, this._width || 0, this._height || 0);
    this._bars  = [];
    this.config = null;
    this.data   = null;
  };

  Chart.prototype.update = function () {
    this._resize();
    this._progress     = 1;
    this._easedProgress = 1;
    this._draw();
  };

  global.Chart = Chart;
})(typeof window !== "undefined" ? window : this);